sql:
SELECT average_rating AS avg_movie_rating
FROM yearly_ratings
WHERE movie_id = 1 AND year = 2013;

SELECT average_rating
FROM monthly_ratings
WHERE movie_id = 0 AND year = 2013 AND month = 9;

external_knowledge:
; A top-rated movie refers to a movie with a high average rating among all the ratings given by active users; 
; Active users are those with 'is_active' status equal to 1; 
; A review is considered valid if it is given by an active user.

sql:
SELECT COUNT(*) AS total_reviews
FROM movie_reviews
WHERE movie_id = 0;

